type State = "analyze" | "analyzing" | "unusable" | "ready" | "processing" | "done" | "failed"

interface TaggedFile {
    file: File
    id: string
    description: string
    state: State
}

let workingSet: TaggedFile[] = []

function content() {
    return `
<main>

<h1>let's resample some audio<span id="exclamation" data-complete="no" title="downloading ffmpeg, please wait">...?</span></h1>
<p>JavaScript required. We're going to run ffmpeg in your browser, so you need a reasonably modern one.</p>

<label id="drop" class="card-common">
    Drop audio media here, or click to select
    <input type="file" id="drop-input" class="hidden" multiple accept="audio/*,application/*">
</label>

<ul id="input-files" class="listless"></ul>

<button id="clear-inputs" class="card-common hidden">
<img src="${ICON_CLEAR}" alt="">
<span>Clear inputs</span>
</button>

</main>
    `
}

function fileElement(file: TaggedFile) {
    const element = document.createElement("li")
    element.dataset.id = file.id
    const first = file.id.split("-")[0]
    element.innerHTML = `
    <div class="-title">${file.file.name}</div>
    <div class="-input-no">${first}</div>
    <button class="-delete"><img src="${ICON_CLEAR}" alt="Delete button"></button>
    <div class="-desc">${file.description}</div>
    `
    return element
}

document.body.innerHTML = content()

const el = {
    exclamation: document.getElementById("exclamation"),
    drop: document.getElementById('drop'),
    dropInput: document.getElementById('drop-input'),
    inputFiles: document.getElementById('input-files'),
    clearInputsBtn: document.getElementById('clear-inputs'),
}

const ffmpeg = new FFmpeg()
const ffmpegPoll: (() => any)[] = []

function ffmpegReady(): Promise<void> {
    return new Promise((resolve, _) => {
        if (ffmpeg.loaded) resolve()
        else ffmpegPoll.push(resolve)
    })
}

async function load() {
    const baseURL = "./vendor/ffmpeg-core"
    ffmpeg.on('log', ({message}) => {
        console.log(message)
    })
    await ffmpeg.load({
        coreURL: await toBlobURL(`${baseURL}/ffmpeg-core.js`, 'text/javascript'),
        wasmURL: await toBlobURL(`${baseURL}/ffmpeg-core.wasm`, 'application/wasm')
    })
    el.exclamation.dataset.complete = "yes"
    el.exclamation.innerText = "!"
    el.exclamation.title = "download complete, ready to go!"
    ffmpegPoll.forEach(it => it())
    ffmpegPoll.length = 0
}

load().then(() => console.info('Got it!'))

function _reorderFileList() {
    let children = el.inputFiles.children;
    shortcut: if (children.length === workingSet.length) {
        for (let i = 0; i < workingSet.length; i++) {
            if ((children[i] as HTMLElement).dataset.id !== workingSet[i].id)
                break shortcut;
        }
        return;
    }
    el.inputFiles.innerHTML = ''
    for (const file of workingSet) {
        el.inputFiles.appendChild(fileElement(file))
    }
}

function _refreshFileKnown(element: HTMLElement, file: TaggedFile) {
    const desc = element.querySelector(".-desc") as HTMLElement
    desc.innerText = file.description
}

function refreshFile(file: TaggedFile) {
    _refreshFileKnown(el.inputFiles.querySelector(`[data-id="${file.id}"]`), file)
}

function refreshFileList() {
    _reorderFileList()
    for (const file of workingSet) {
        refreshFile(file)
    }
    if (workingSet.length > 0) {
        el.clearInputsBtn.classList.remove('hidden')
    } else {
        el.clearInputsBtn.classList.add('hidden')
    }
}

function addFile(file: File) {
    console.log(file)
    if (!file.type.startsWith("audio/") && !file.type.startsWith("application/")) return
    const item = {
        file: file,
        id: crypto.randomUUID(),
        description: "not sure what this is yet, hold on",
        state: "analyze" as const
    };
    workingSet.push(item)
    el.inputFiles.appendChild(fileElement(item))
    refreshFileList()
}

function handleDrop(ev: DragEvent) {
    ev.preventDefault()
    const files = [...ev.dataTransfer.items]
        .map(it => it.getAsFile())
        .filter(it => it)
    files.forEach(addFile)
    refreshFileList()
    el.drop.classList.remove("-hint")
}

// Set up the dropzone
el.drop.addEventListener("drop", handleDrop)
window.addEventListener("drop", e => {
    console.log('window', e)
    // thanks MDN https://developer.mozilla.org/en-US/docs/Web/API/HTML_Drag_and_Drop_API/File_drag_and_drop
    // el.drop.classList.remove("-hint")
    if ([...e.dataTransfer.items].some((item) => item.kind === "file")) {
        e.preventDefault();
    }
})
el.drop.addEventListener("dragover", e => {
    const fileItems = [...e.dataTransfer.items].filter(
        (item) => item.kind === "file",
    );
    if (fileItems.length > 0) {
        e.preventDefault();
        e.dataTransfer.dropEffect = "copy";
    }
})
window.addEventListener("dragover", e => {
    const fileItems = [...e.dataTransfer.items].filter(
        (item) => item.kind === "file",
    );
    if (fileItems.length > 0) {
        e.preventDefault();
        if (!el.drop.contains(e.target as Node)) {
            e.dataTransfer.dropEffect = "none";
        }
        el.drop.classList.add("-hint")
    } else {
        el.drop.classList.remove("-hint")
    }
});
el.dropInput.addEventListener("change", e => {
    const target = e.target as HTMLInputElement;
    for (const file of target.files) {
        addFile(file)
    }
    refreshFileList()
    target.value = null;
})
window.addEventListener("dragleave", () => el.drop.classList.remove("-hint"));
window.addEventListener("dragend", () => el.drop.classList.remove("-hint"));

function failFile(file: TaggedFile, reason: any) {
    console.error(reason)
    file.state = "unusable"
    file.description = `can't process this file: ${reason}`
    refreshFile(file)
    return
}

async function processAnalyze(file: TaggedFile) {
    if (file.state !== "analyze") throw "wrong state dumbass"
    file.state = "analyzing"
    file.description = "waiting for FFmpeg..."
    refreshFile(file)
    await ffmpegReady()
    file.description = "working on it..."
    refreshFile(file)
    await ffmpeg.writeFile(file.id, await fetchFile(file.file))
    const statFile = `${file.id}-stat.txt`
    await ffmpeg.ffprobe([
        '-v', 'error',
        '-select_streams', 'a:0',
        '-of', 'default=nw=1',
        '-show_entries',
        'stream=bit_rate,channels,codec_name',
        file.id,
        '-o', statFile
    ])
    try {
        const data = new TextDecoder().decode(await ffmpeg.readFile(statFile) as Uint8Array)
        const channelMatch = data.match(/channels=(\d+)/)
        const bitrateMatch = data.match(/bit_rate=(\d+)/)
        const codecMatch = data.match(/codec_name=(.+)/)
        if (channelMatch === null || bitrateMatch === null || codecMatch === null)
            return failFile(file, "cannot extract audio channel (not audio?)")

        const channel = +channelMatch[1]
        const bitrate = +bitrateMatch[1]

        let channelName: string
        if (channel === 0) return failFile(file, "channel count is 0")
        if (channel === 1) channelName = "mono"
        else if (channel === 2) channelName = "stereo"
        else channelName = "surround?"

        file.state = "ready"
        file.description = `${codecMatch[1]} audio: ${bitrate} bits per second, ${channel} channel${channel == 1 ? '' : 's'} (${channelName})`
        refreshFile(file)
    } catch (e) {
        return failFile(file, e)
    } finally {
        // noinspection ES6MissingAwait
        ffmpeg.deleteFile(statFile)
    }
}

function step() {
    for (const file of workingSet) {
        switch (file.state) {
            case "analyze": // noinspection JSIgnoredPromiseFromCall
                processAnalyze(file)
                break;
        }
    }
}

setInterval(step, 100)

